parameters.functionCode:
const response = $input.first().json;
const docType = response.content[0].text.trim();
const fileName = $('Read Document').first().json.fileName;

const folderMap = {
  'MOTION': 'Motions',
  'COMPLAINT': 'Pleadings',
  'ANSWER': 'Pleadings',
  'DISCOVERY_REQUEST': 'Discovery',
  'DISCOVERY_RESPONSE': 'Discovery',
  'BRIEF': 'Briefs',
  'CONTRACT': 'Contracts',
  'SETTLEMENT_AGREEMENT': 'Settlements',
  'COURT_ORDER': 'Orders',
  'CORRESPONDENCE': 'Correspondence',
  'OTHER': 'Uncategorized'
};

const targetFolder = folderMap[docType] || 'Uncategorized';

const fs = require('fs');
const oldPath = `/home/user/LegalDocs/Inbox/${fileName}`;
const newPath = `/home/user/LegalDocs/${targetFolder}/${fileName}`;
fs.renameSync(oldPath, newPath);

return [{json: {fileName, docType, targetFolder, moved: true}}];
